            aOrbiterG = (((aWandererC + RotL64(aIngress, 46U)) + RotL64(aCarry, 47U)) + 0xD8B90824A219101FULL) + aPhaseHOrbiterAssignSaltC[((aIndex + 15U)) & S_SALT1];
            aOrbiterH = (aWandererG + RotL64(aCross, 41U)) + 0xDCDCEBBFB5CAA771ULL;
