            aOrbiterJ = ((aWandererE + RotL64(aScatter, 56U)) + 0xA4C612B9BE76451DULL) + aPhaseHOrbiterAssignSaltD[(((31U - aIndex) + 17U)) & S_SALT1];
            //
            aOrbiterA = (aOrbiterA + aOrbiterD) + 0xA32FA517BCD45DB7ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterA) ^ 0x8D6D1AF3B1AC991DULL;
            aOrbiterG = RotL64((aOrbiterG * 0x3AE3E55DA3D79349ULL), 37U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterA) + 0x81433C775DBAFCADULL) + aPhaseHOrbiterUpdateSaltA[((aIndex + 10U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterH) ^ 0xA057985676D06233ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x6A8969CD13114B23ULL), 19U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterB) + 0x4BA9223F0E3FBF69ULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterC) ^ 0x656FC6BCA096FBA0ULL) ^ aPhaseHOrbiterUpdateSaltF[(((31U - aIndex) + 16U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0xC551E83019A218A3ULL), 57U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterE) + 0xF21BA8452B7C1B69ULL) + aPhaseHOrbiterUpdateSaltC[(((31U - aIndex) + 18U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterB) ^ 0x0AC59E05F24C7214ULL;
            aOrbiterH = RotL64((aOrbiterH * 0xAC6DE5A48131E6F3ULL), 11U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterC) + 0x14B0BCF9B35C5213ULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterE) ^ 0x65E93269CC4061DEULL) ^ aPhaseHOrbiterUpdateSaltB[((aIndex + 23U)) & S_SALT1];
