            aWandererC = aWandererC + (((RotL64(aScatter, 29U) + RotL64(aOrbiterB, 3U)) + aOrbiterH) + aPhaseHWandererUpdateSaltC[((aIndex + 9U)) & S_SALT1]);
            aWandererK = aWandererK ^ ((RotL64(aPrevious, 43U) + RotL64(aOrbiterC, 13U)) + aOrbiterF);
            aWandererG = aWandererG + (((RotL64(aIngress, 51U) + RotL64(aOrbiterD, 27U)) + aOrbiterE) + RotL64(aCarry, 3U));
            aWandererB = aWandererB ^ (((RotL64(aCross, 57U) + RotL64(aOrbiterC, 18U)) + aOrbiterD) + aPhaseHWandererUpdateSaltD[(((31U - aIndex) + 27U)) & S_SALT1]);
            aWandererH = aWandererH + (((RotL64(aScatter, 47U) + RotL64(aOrbiterD, 43U)) + aOrbiterA) + RotL64(aCarry, 47U));
            aWandererD = aWandererD ^ ((RotL64(aIngress, 38U) + aOrbiterF) + RotL64(aOrbiterG, 39U));
            //
